import React, { useEffect, useState } from "react";
import { useNavigate } from "react-router-dom";
import "./studentDashboard.css";
import http from "../utils/http.js";

const StudentDashboard = () => {
  const navigate = useNavigate();
  const [tab, setTab] = useState("overview");
  const [profile, setProfile] = useState({});
  const [mentors, setMentors] = useState([]);
  const [meetings, setMeetings] = useState([]);
  const [reports, setReports] = useState([]);
  const [requests, setRequests] = useState([]);
  const [error, setError] = useState("");

  const [selectedMentor, setSelectedMentor] = useState("");
  const [projTitle, setProjTitle] = useState("");
  const [projDomain, setProjDomain] = useState("");
  const [projDesc, setProjDesc] = useState("");
  const [reportFile, setReportFile] = useState(null);

  const userId = localStorage.getItem("userId");
  const token = localStorage.getItem("token");
  const role = localStorage.getItem("role");

  const loadAll = async () => {
    const [p, m, meet, rep, req] = await Promise.all([
      http.get("/api/students/me"),
      http.get("/api/mentors"),
      http.get(`/api/students/meetings/${userId}`),
      http.get(`/api/students/reports/${userId}`),
      http.get(`/api/students/requests/${userId}`),
    ]);
    setProfile(p.data);
    setMentors(m.data);
    setMeetings(meet.data);
    setReports(rep.data);
    setRequests(req.data);
  };

  useEffect(() => {
    if (!token || role !== "student") {
      navigate("/login");
      return;
    }
    loadAll();
  }, [token, role, navigate, userId]);

  const handleLogout = () => {
    localStorage.clear();
    navigate("/login");
  };

  const submitProject = async (e) => {
    e.preventDefault();
    const { data } = await http.post("/api/mentor-requests", {
      mentor_id: selectedMentor,
      project_title: projTitle,
      domain: projDomain,
      description: projDesc,
    });
    if (data.message) {
      setProjTitle(""); setProjDomain(""); setProjDesc(""); setSelectedMentor("");
      loadAll();
    }
  };

  const uploadReport = async (e) => {
    e.preventDefault();
    const form = new FormData();
    form.append("report", reportFile);
    await http.post("/api/reports/upload", form);
    setReportFile(null);
    loadAll();
  };

  return (
    <div className="student-dashboard">
      {/* ... (same UI as before, uses http.get/post) */}
      {/* Overview, Project, Mentors tabs */}
    </div>
  );
};

export default StudentDashboard;
